#include <stdio.h>
#include <time.h>

// Simulate register access (immediate)
int register_access(int *reg) {
    return *reg;  // Direct access - fastest
}

// Simulate cache access (array in cache)
int cache_access(int arr[100], int index) {
    // If in cache (first 10 accesses), fast
    return arr[index];
}

// Simulate RAM access with timing
clock_t ram_access(int *ram, int address) {
    clock_t start = clock();
    int data = ram[address];  // Memory access latency
    return clock() - start;
}

int main() {
    int register_var = 100;
    int cache_array[100];
    int ram_array[1000];

    // Initialize arrays
    for(int i=0; i<100; i++) cache_array[i] = i;
    for(int i=0; i<1000; i++) ram_array[i] = i;

    // Access examples
    int reg_val = register_access(&register_var);  // Register
    int cache_val = cache_access(cache_array, 5);  // Cache
    int ram_val = ram_access(ram_array, 500);      // RAM

    printf("Register: %d, Cache: %d, RAM: %d\n", 
           reg_val, cache_val, ram_val);
    return 0;
}
